from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismPopupNode(BaseNode):
    name = "Prism: Popup"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("message", "string", widget_type="text_area", default="Hello from Vibrante!")
        self.add_input("title", "string", widget_type="text", default="Prism")
        self.add_output("shown", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        msg = inputs.get('message') or ''
        title = inputs.get('title') or 'Prism'
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'shown': False}
        try:
            try:
                core.popup(msg, title=title)
            except TypeError:
                core.popup(msg)
            self.log_info(f"Popup: {msg}")
            await self.set_output('exec_out', True)
            return {'shown': True}
        except Exception as e:
            self.log_error(f"popup failed: {e}")
            return {'shown': False}

def register_node():
    return PrismPopupNode
